function changeFieldToHidden(logger) {
  return function (passInput) {
    if (!passInput) {
      return;
    }

    function change(input) {
      if (!!input && input.getAttribute && input.setAttribute) {
        var origAttr = input.getAttribute("type");
        input.setAttribute("type", "hidden");
        input.setAttribute("portadiHiddenPass", "1");
        setTimeout(function () {
          input.setAttribute("type", origAttr);
          input.removeAttribute("portadiHiddenPass");
        }, 2000);
      }
    }

    change(passInput);
    //hide all other password inputs to prevent storing some hidden password inputs (as in Doodle)
    var otherPassInputs;
    if (window.ONELOGIN_Sizzle) {
      otherPassInputs = window.ONELOGIN_Sizzle("input[type=password]");
    } else {
      otherPassInputs = document.querySelectorAll("input[type=password]");
    }
    for (var i = 0; i < otherPassInputs.length; i++) {
      change(otherPassInputs[i]);
    }
  };
}

function changeFieldToPass(logger) {
  return function (emailInput) {
    if (!!emailInput && emailInput.getAttribute && emailInput.setAttribute) {
      var origAttr = emailInput.getAttribute("type");
      emailInput.setAttribute("type", "password");
      setTimeout(function () {
        emailInput.setAttribute("type", origAttr);
      }, 2000);
    }
  };
}

