function findPasswordSelector(loginFn) {
  var passwordFieldSelector;
  var loginFnCode = loginFn.toString();

  //find in i.e. document.getElementById('id_username').value = params.username;
  var passwordMatch = /(.*)\.value[\s]*=[\s]*(params\.password|api.getPassword\(\)).*/.exec(
    loginFnCode
  );
  if (
    (passwordMatch && passwordMatch[1] && passwordMatch[1].trim() === "password") ||
    !passwordMatch ||
    !passwordMatch[1]
  ) {
    passwordMatch = /var[\s]*password[\s]*=[\s]*([^;\s]*);/.exec(loginFnCode);
  }

  if (passwordMatch && passwordMatch[1]) {
    passwordFieldSelector = passwordMatch[1].trim();
  }

  return passwordFieldSelector;
}

function preventPasswordByPassTypeCode(loginFn) {
  var code = function (api) {
    if (!document.body) {
      api.log("preventPasswordByPassTypeCode document.body is not defined -> api.WAIT");
      return api.WAIT;
    }
    var fieldSelector = $FIELD_SELECTOR;
    var preventPasswordByPassTypeFn = $PREVENT_PASSWORD_FN(api);
    api.log("Applying prevent password on:", fieldSelector);
    preventPasswordByPassTypeFn(fieldSelector);
    return api.NEXT;
  }.toString();

  var fieldSelector = findPasswordSelector(loginFn);
  //logger.debug("Password field selector:", fieldSelector);
  if (fieldSelector) {
    code = code.replace("$FIELD_SELECTOR", fieldSelector);
    code = code.replace("$PREVENT_PASSWORD_FN", changeFieldToHidden.toString());
  } else {
    // logger.warn("Failed to prevent password. Password field selector not found for loginFn:", loginFn);
    return function (api) {
      api.log("Failed to prevent password. Password selector not found");
      return api.NEXT;
    }.toString();
  }

  return code;
}
export default {
  changeFieldToHidden,
  changeFieldToPass,
  preventPasswordByPassTypeCode,
};
