function perform_login_wrapper(
  disable_browser_password_manager,
  auto_submit,
  values,
  form_value,
  form_attr,
  form_submitted_by,
  submit_value,
  submit_attr
) {
  var perform_login = function (doc) {
    if (doc.getElementById("onelogin_dialog"))
      doc.getElementById("onelogin_dialog").style.visibility = "hidden";

    var fieldlist = new Array();

    Object.entries(values || {}).map(([name, value]) => {
      fieldlist.push([name, value]);
    });

    var forms = doc.getElementsByTagName("form");
    var submit_button = null;

    // var reg = /<%= form_value %>/;
    var reg = new RegExp(form_value);

    for (var i = 0; i < forms.length; i++) {
      let form_attrs = forms[i].attributes.getNamedItem(form_attr);
      if (form_attrs && reg.test(form_attrs.value)) {
        var form = forms[i];
        break;
      }
    }

    //Did not find a form in the document
    if (i == forms.length) {
      var getLocalIframes = function (doc) {
        var orig_iframes = doc.getElementsByTagName("iframe");

        var ret_iframes = [];
        for (var i = 0; i < orig_iframes.length; i++) {
          try {
            if (orig_iframes[i].contentDocument) {
              ret_iframes.push(orig_iframes[i]);
            }
          } catch (e) {
            continue;
          }
        }
        return ret_iframes;
      };

      var iframes = getLocalIframes(document);

      if (iframes.length > 0) {
        for (var k = 0; k < iframes.length; k++) {
          var iframe = iframes[k];
          var doc = iframe.contentDocument;
          var forms = doc.forms;
          for (var l = 0; l < forms.length; l++) {
            var form = forms[l];
            let form_attrs = form.attributes.getNamedItem(form_attr);
            if (form_attrs && reg.test(form_attrs.value)) break;
          }
        }
      }
    }

    //we did not find any forms, nor on the main document, nor on local iframes.
    if (!form) return;

    var fields = form.getElementsByTagName("input");

    if (fields.length == 0) fields = form.elements;

    for (var j = 0; j < fields.length; j++) {
      // <% if self.form_submitted_by == 'button' %>
      //    if (f = fields[j].attributes.getNamedItem('<%= self.submit_attr %>')) {
      //             if (f.value == '<%= self.submit_value %>') {
      //                 submit_button = fields[j];
      //             }
      //         }
      // <% end %>

      if (form_submitted_by === "button") {
        var f = fields[j].attributes.getNamedItem(submit_attr);
        if (f) {
          if (f.value == submit_value) {
            submit_button = fields[j];
          }
        }
      }

      for (var n = 0; n < fieldlist.length; n++) {
        var f = fields[j].attributes.getNamedItem("name");
        if (f) {
          if (f.value == fieldlist[n][0]) fields[j].value = fieldlist[n][1];
          try {
            if (fields[j].type == "password"&& disable_browser_password_manager) {
              var passField = fields[j];
              if (passField.getAttribute && passField.setAttribute)
                passField.setAttribute("type", "hidden");
            }
          } catch (err) {}
        }
      }
    }

    // <% if self.form_submitted_by == 'button' %>
    if (form_submitted_by === "button") {
      var buttons = form.getElementsByTagName("button");
      for (var j = 0; j < buttons.length; j++) {
        var f = buttons[j].attributes.getNamedItem(submit_attr);
        if (f) {
          if (f.value == submit_value) {
            submit_button = buttons[j];
          }
        }
      }

      if (auto_submit) {
        if (submit_button != null) {
          submit_button.click();
        } else {
          form.submit();
        }
      }
    } else {
      submit_value;
    }
  };

  return perform_login;
}

export default perform_login_wrapper;
