function transformStepNameToFunctions(steps) {
  let updatedStepsWithFunctions = [];

  updatedStepsWithFunctions = [
    premadeSteps.reportLevel,
    ...steps.map((step) => {
      if (typeof step === "string") {
        if (!premadeSteps[step]) {
          throw new Error(`unknown preMadeStep ${step}`);
        }
        return premadeSteps[step];
      } else if (typeof step === "function") {
        console.log("Step function created : ", premadeSteps.encaseFn(step, `Onelogin script`));
        return premadeSteps.encaseFn(step, `Onelogin script`);
      } else {
        throw new Error(`unknown step ${JSON.stringify(step)}`);
      }
    }),
  ];

  return updatedStepsWithFunctions;
}

/**
 * This method returns the function that needs to be injected and executed.
 *
 * `use_form_service` value is saved for each connector in the connectors table.
 *
 * Conditions that needs to be met to get the function to be executed is as follows:
 *  1. If login_steps is found return the login steps wby replacing the step name with the actual premade step functions
 *  2. if not, then
 *          1. Based on the auth_method/login_type we either generate the script in core-api or use the login_script field in
 *              db or use the form service defined script generation (look at the conditions in forms_type.rb and related connectors
 *              file . and connectors.rb file in core-api)
 *          2. Transform the steps according to the logic defined in forms service
 *
 */
function getLoginStepsForTheConnector(
  connectorId,
  dynamic_form_values,
  form_value,
  form_attr,
  form_submitted_by,
  submit_value,
  submit_attr,
  use_form_service,
  auth_method,
  login_method,
  login_type
) {
  if (login_type === "basic") {
    return premadeSteps.basicAuthSteps;
  }

  /**
   * Verify this once at the end
   * Because all this login_type uses
   */
  if (["API", "OPENID", "Other Type", "SAML"].includes(login_type)) {
    return premadeSteps.standardLogin;
  }

  // Currently writing it for only froms_type.rb file, need to include all types of connectors
  // forms_type, open_id_type, basic_auth_type,saml_type,post_type,forms_type,api_type,google_type

  if (use_form_service && !connectorToStepsMapping[connectorId]) {
    /**
     * Generate the login steps using the logic defined in the form service
     */
    return premadeSteps.standardLogin;
  } else {
    if (use_form_service && connectorToStepsMapping[connectorId]) {
      /**
       * Transform the steps by replacing function names with the premadesteps function and then
       * return the array.
       */
      return transformStepNameToFunctions(connectorToStepsMapping[connectorId]);
    } else {
      if (login_method === "script") {
        if (use_form_service) {
          /**
           * Return the generic connector script
           */
          const generic_script = genericConnector();
          return premadeSteps.oneloginStepsWithReadyState(generic_script);
        } else {
          // Return the oneloginn script
          // make it steps using premade scripts and then return it.
          if (connectorToScriptMapping[connectorId]) {
            return premadeSteps.oneloginStepsWithReadyState(connectorToScriptMapping[connectorId]);
          }
        }
      } else {
        /**
         * Use the function by referring to the perform_login.js.rb template in core-api
         * convert this using the form-service wrapper
         */
        const onelogin_script = perform_login_wrapper(
          true,
          true,
          dynamic_form_values,
          form_value,
          form_attr,
          form_submitted_by,
          submit_value,
          submit_attr
        );
        return premadeSteps.oneloginStepsWithReadyState(onelogin_script, true);
      }
    }
  }

  /**
   * Return the standard Login steps from form-service. (using premade steps)
   */

  return premadeSteps.standardLogin;
}

