import goToLoginStepFuncCode from "./goToLoginStepFunc.js";
import autoLoginFuncCode from "./autoLoginStepFunc.js";

var preMadeSteps = {
  reportLevel: {
    name: "Set report level",
    context: "Background",
    code: function (api) {
      var userContext = api.getUserContext();
      userContext.reportLevel = "normal";
    },
  },
  cloak: {
    name: "Cloak",
    context: "Content",
    code: function (api) {
      if (api.cloak) {
        // api.cloak();
      } else {
        api.log("cloak not supported");
      }
      return api.NEXT;
    },
  },

  goToUrl: function (url) {
    var code = function (api) {
      api.setLocation(url);
      return api.NEXT;
    };
    return {
      name: "Go to URL",
      context: "Content",
      code: code,
    };
  },

  goToLoginUrl: {
    name: "Go to login URL",
    context: "Content",
    code: function (api) {
      var loginUrl = api.getLoginUrl();
      // var match = /https?:\/\/([^\/]+)/.exec(loginUrl);
      // if (!!match && match[1]) {
      // 	api.clearCookie(match[1], /.*/);
      // }
      api.setLocation(loginUrl);
      return api.NEXT;
    },
  },

  goToLoginUrlWithWWWAuthentication: {
    name: "Go to URL with basic authentication",
    context: "Content",
    code: function (api) {
      var authParams = {
        username: api.getUsername(),
        password: api.getPassword(),
      };
      api.setLocation(api.getLoginUrl(), authParams);
      return api.NEXT;
    },
  },

  stopIfWWWAuthenticationPerformed: {
    name: "Stop if WWW authentication performed",
    context: "Background",
    code: function (api) {
      if (api.wasWWWAuthenticationPerformed && api.wasWWWAuthenticationPerformed()) {
        api.log("WWW Authentication performed, stopping");
        return api.SUCCESS;
      }
      return api.NEXT;
    },
  },

  uncloak: {
    name: "Uncloak",
    context: "Background",
    code: function (api) {
      api.uncloak();
    },
  },
  readyState: {
    name: "Wait to stabilize page",
    context: "Content",
    code: function (api) {
      if (!document.body) {
        api.log("preMadeSteps.readyState document.body is not defined -> api.WAIT");
        return api.WAIT;
      }
      if (api.waitForReady) {
        api.waitForReady();
      } else {
        api.log("wait for ready not supported");
      }
      api.log("wait for ready finished");
      return api.NEXT;
    },
  },
  basicAuth: {
    name: "Basic authentication",
    context: "Content",
    code: function (api) {
      var loginUrl = api.getLoginUrl(),
        hasBrowserAuthentication =
          !api.getCapabilities || api.getCapabilities().basicAuthentication; //first versions of chrome supported browserAuthentication, but haven't had getCapabilities

      if (hasBrowserAuthentication) {
        api.log("Browser supports basic auth");
        var authParams = {
          username: api.getUsername(),
          password: api.getPassword(),
        };
        // var loginUrl = api.getLoginUrl();
        // var match = /https?:\/\/([^\/]+)/.exec(loginUrl);
        // if (!!match && match[1]) {
        // 	api.clearCookie(match[1], /.*/);
        // }
        api.setLocation(loginUrl, authParams);
        return api.NEXT;
      } else {
        var basicAuthUrl = api.getBasicAuthUrl() || loginUrl,
          match = basicAuthUrl.match(/^(https?:\/\/)(.*)$/);

        api.log("Browser does not support basic auth, fallback");
        if (match.length === 3) {
          var urlWithCreds =
              match[1] +
              encodeURIComponent(api.getUsername()) +
              ":"+
              encodeURIComponent(api.getPassword()) +
              "@"+
              match[2],
            xhr = new XMLHttpRequest();

          api.log("Processing basic auth against "+ basicAuthUrl);
          xhr.open("GET", urlWithCreds);
          xhr.send();
          api.waitForReady(); //to wait until the xhr finishes
          api.setLocation(loginUrl);
          return api.NEXT;
        } else {
          api.log("Failed to parse basicAuthUrl "+ basicAuthUrl);
          return api.FAIL;
        }
      }
    },
  },
  showLoginDialog: {
    name: "Show login dialog",
    context: "Content",
    code: goToLoginStepFuncCode(),
  },
  waitForPredicate: function (continuePredicateFn, failurePredicateFn, maxWait) {
    var code = function (api) {
      if (!document.body) {
        api.log("preMadeSteps.waitForPredicate document.body is not defined -> api.WAIT");
        return api.WAIT;
      }
      var continueFn = continuePredicateFn;
      var failureFn = failurePredicateFn
        ? failurePredicateFn
        : function () {
            return false;
          };
      var wait = maxWait ? maxWait.toString() : 5000;
      if (continueFn()) {
        api.log("wait for predicate finished -> continuing");
        return api.NEXT;
      }
      if (api.getStepTime() >= wait) {
        api.log("timeout waiting for predicate");
        return api.NEXT;
      }
      if (failureFn()) {
        api.log("failure predicate is true");
        return api.FAILURE;
      }
      return api.WAIT;
    };

    if (typeof failurePredicateFn === "number") {
      //if failurePredicate is missing
      maxWait = failurePredicateFn;
      failurePredicateFn = undefined;
    }

    return {
      name: "Wait for predicate",
      context: "Content",
      code: code,
    };
  },
  autoLogin: {
    name: "Auto login",
    context: "Content",
    code: autoLoginFuncCode(true),
  },
};

preMadeSteps.basicAuthSteps = [preMadeSteps.cloak, preMadeSteps.basicAuth, preMadeSteps.uncloak];

preMadeSteps.encaseFn = (fn, name = "Onelogin script") => ({
  name,
  context: "Content",
  code: function (api) {
    if (!document.body) {
      api.log("defaultEncaseFnString document.body is not defined -> api.WAIT");
      return api.WAIT;
    }
    var encasedFn = fn;
    return encasedFn(api) || api.NEXT;
  },
});

preMadeSteps.encaseFnForScript = (fn, name = "Onelogin script") => ({
  name,
  context: "Content",
  code: function (api) {
    if (!document.body) {
      api.log("defaultEncaseFnString document.body is not defined -> api.WAIT");
      return api.WAIT;
    }
    var encasedFn = fn;
    return encasedFn(api) || api.NEXT;
  },
});

preMadeSteps.encaseFnForScriptDoc = (fn, name = "Onelogin script") => ({
  name,
  context: "Content",
  code: function (api) {
    if (!document.body) {
      api.log("defaultEncaseFnString document.body is not defined -> api.WAIT");
      return api.WAIT;
    }
    var encasedFn = fn;
    return encasedFn(document) || api.NEXT;
  },
});

preMadeSteps.oneloginStepsWithReadyState = function (oneloginScript, use_doc = false) {
  return [
    preMadeSteps.reportLevel,
    preMadeSteps.cloak,
    preMadeSteps.goToLoginUrl,
    preMadeSteps.readyState,
    use_doc
      ? preMadeSteps.encaseFnForScriptDoc(oneloginScript)
      : preMadeSteps.encaseFnForScript(oneloginScript),
    preMadeSteps.uncloak,
  ];
};

preMadeSteps.waitForPasswordField = preMadeSteps.waitForPredicate(function () {
  return window.ONELOGIN_Sizzle
    ? window.ONELOGIN_Sizzle('input[type="password"]').length > 0
    : document.querySelectorAll('input[type="password"]').length > 0;
});

//standard form-based login (no basic auth)
preMadeSteps.standardLogin = [
  preMadeSteps.cloak,
  preMadeSteps.goToLoginUrl,
  preMadeSteps.readyState,
  preMadeSteps.showLoginDialog,
  preMadeSteps.waitForPasswordField,
  preMadeSteps.autoLogin,
  preMadeSteps.uncloak,
];

export default preMadeSteps;
