import submitFunc from "./submit.js";
import findInputsFunc from "./findInputs.js";
import fillInputFunc from "./fillInput.js";
import preventPassByPassType from "./preventPassByPassType.js";

var changeFieldToHidden = preventPassByPassType.changeFieldToHidden;

export default function autoLoginStepFunc(doSubmit) {
  var code = function (api) {
    if (!document.body) {
      api.log("autoLoginStepFunc document.body is not defined -> api.WAIT");
      return api.WAIT;
    }
    var submitFn = doSubmit
      ? submitFunc(api)
      : function () {
          return function () {};
        };
    var findInputsFn = findInputsFunc(api);
    var fillInputFn = fillInputFunc(api);
    var preventPasswordByPassTypeFn = changeFieldToHidden(api);

    var inputs = findInputsFn(document.body, true);
    if (inputs) {
      if (inputs.login) {
        fillInputFn(inputs.login, api.getUsername());
      } else {
        api.log("Username input not found.");
        return api.FAILURE;
      }

      if (inputs.pass) {
        fillInputFn(inputs.pass, api.getPassword());
      } else {
        api.log("Password input not found.");
        return api.FAILURE;
      }

      preventPasswordByPassTypeFn(inputs.pass);
      submitFn(inputs.login);
    } else {
      api.log("Form not filled. Inputs not returned.");
      return api.FAILURE;
    }

    return api.NEXT;
  };

  if (doSubmit === undefined) {
    doSubmit = true;
  }

  return code;
}
