import findGoToLogin from "./findGoToLogin.js";
import findInputs from "./findInputs.js";

export default function goToLoginStepFun() {
  var code = function (api) {
    if (!document.body) {
      // document.body can be null
      // script executed too early on the page
      api.log("gotoLoginStepFunc document.body is not defined -> api.WAIT");
      return api.WAIT;
    }

    var findGoToLoginFn = findGoToLogin(api);
    var findInputsFn = findInputs(api);

    var inputs = findInputsFn(document.body, false);
    if (!inputs) {
      api.log("No inputs. Finding goto login button.");
      var gotoLoginButton = findGoToLoginFn(document.body);
      if (!gotoLoginButton) {
        inputs = findInputsFn(document.body, true); //findInputs with flag afterFindGotoLogin (it tolerates hidden passwords)
        if (!inputs) {
          api.log("No inputs nor goto login button found.");
          if (api.getStepTime() >= 5000) {
            api.log("timeout waiting for input buttons or goto login");
            return api.FAILURE;
          } else {
            return api.WAIT; //lets wait for at least some element
          }
        }
      } else {
        gotoLoginButton.el.click();
        api.waitForReady();
      }
    }
    return api.NEXT;
  };

  return code;
}
